code = """import re\nimport json\nimport pandas as pd\nimport ast\n\nbusiness_data_raw_string = locals()['var_function-call-6524883148547350284']['results'][0]\n\n# Extract the JSON part from the string\n# This assumes the result format is consistent: some text followed by the JSON array.\n# Let's find the first '[' and the last ']' to extract the JSON.\njson_start_index = business_data_raw_string.find(\'[{\')\njson_end_index = business_data_raw_string.rfind(\'}]\') + 2\n\n# Fallback for simpler json string that don\'t have the full context info in the beginning (e.g., if there are no records)\nif json_start_index == -1 or json_end_index == -1:\n    json_start_index = business_data_raw_string.find(\'[\')\n    json_end_index = business_data_raw_string.rfind(\']\') + 1\n\nbusiness_data_json_str = business_data_raw_string[json_start_index:json_end_index].strip()\nbusiness_data = json.loads(business_data_json_str)\n\ndef parse_location_and_wifi(record):\n    business_id = record[\'business_id\']\n    description = record[\'description\']\n    attributes_raw = record.get(\'attributes\')\n\n    state = None\n    # Regex to extract the two-letter state code, ensuring it\'s capitalized and preceded by a comma and space.\n    match = re.search(r\', ([A-Z]{2}),\', description)\n    if match:\n        state = match.group(1)\n\n    wifi = False # Default to False if WiFi attribute is missing or ambiguous\n\n    if attributes_raw:\n        if isinstance(attributes_raw, dict):\n            wifi_val = attributes_raw.get(\'WiFi\')\n            if wifi_val in [\"True\", True, \'True\']:\n                wifi = True\n        elif isinstance(attributes_raw, str):\n            try:\n                # Attempt to parse string representation of attributes as a dictionary\n                # Replace single quotes with double quotes for JSON parsing\n                # Also handle \'u\'\' style unicode literal in strings\n                # Use a regex to make sure keys are double quoted before json.loads\n                # and boolean/None values are lowercase\n                attr_dict_str = attributes_raw.replace(\"u\'\", \"\'\")\n                attr_dict_str = re.sub(r\"([{,]\s*)(\\w+)(\s*:)\", r\'\\1\"\\2\"\\3\', attr_dict_str)\n                attr_dict_str = attr_dict_str.replace(\"\'\", \'\"\').replace(\"True\", \"true\").replace(\"False\", \"false\").replace(\"None\", \"null\")\n\n                attr_dict = json.loads(attr_dict_str)\n                wifi_val = attr_dict.get(\'WiFi\')\n                if wifi_val in [\"true\", True, \'True\']:\n                    wifi = True\n            except json.JSONDecodeError:\n                try:\n                    # Fallback for more complex or malformed string dictionaries using ast.literal_eval\n                    # Replace u'' with '' for ast.literal_eval to work correctly\n                    attr_dict = ast.literal_eval(attributes_raw.replace(\"u\'\", \"\'\"))\n                    wifi_val = attr_dict.get(\'WiFi\')\n                    if wifi_val in [\"True\", True, \'True\']:\n                        wifi = True\n                except (ValueError, SyntaxError) as e:\n                    # print(f\"AST literal_eval failed for: {attributes_raw}. Error: {e}\") # For debugging\n                    pass\n    return {\n        \'business_id\': business_id,\n        \'state\': state,\n        \'wifi_available\': wifi\n    }\n\nprocessed_businesses = [parse_location_and_wifi(record) for record in business_data]\n\nwifi_businesses_df = pd.DataFrame([b for b in processed_businesses if b[\'wifi_available\'] == True and b[\'state\'] is not None])\n\nhighest_state_name = None\nhighest_state_count = 0\nbusiness_ids_in_highest_state = []\n\nif not wifi_businesses_df.empty:\n    state_counts = wifi_businesses_df[\'state\'].value_counts().reset_index()\n    state_counts.columns = [\'state\', \'wifi_business_count\']\n\n    highest_state = state_counts.loc[state_counts[\'wifi_business_count\'].idxmax()]\n    highest_state_name = highest_state[\'state\']\n    highest_state_count = highest_state[\'wifi_business_count\']\n    business_ids_in_highest_state = wifi_businesses_df[wifi_businesses_df[\'state\'] == highest_state_name][\'business_id\'].tolist()\n\nprint(\"__RESULT__:\")\nprint(json.dumps({\n    \'highest_state_name\': highest_state_name,\n    \'highest_state_count\': int(highest_state_count),\n    \'business_ids_in_highest_state\': business_ids_in_highest_state\n}))"""

